const BY_HEX = new Map(NAMED_COLORS.map((c) => [c.hex, c]));
const BY_SLUG = new Map(NAMED_COLORS.map((c) => [c.slug, c]));

export function findByHex(hex: Hex): NamedColor | undefined {
  return BY_HEX.get(hex.toLowerCase());
}

export function findBySlug(slug: string): NamedColor | undefined {
  return BY_SLUG.get(slug);
}

export function byFamily(family: ColorFamily): NamedColor[] {
  return NAMED_COLORS.filter((c) => c.family === family);
}
